> new file mode 100644
> index 000000000000..c264cc625a7c
> --- /dev/null
> +++ b/tools/testing/selftests/mm/folio_split_race_test.c
[ ... ]
> +/* Returns true if valid, false if corrupted. */
> +static bool check_page(unsigned char *base, size_t page_idx)
> +{
> +	unsigned char *page_ptr = base + page_idx * page_size;
> +	uint64_t expected_idx = (uint64_t)page_idx;
> +	uint64_t got_idx;
> +
> +	memcpy(&got_idx, page_ptr, 8);
> +
> +	if (got_idx != expected_idx) {
> +		size_t off;
> +		int all_zero = 1;
> +
> +		for (off = 0; off < page_size; off++) {
> +			if (page_ptr[off] != 0) {
> +				all_zero = 0;
> +				break;
> +			}
> +		}
> +		if (all_zero) {
> +			ksft_print_msg(
> +				"CORRUPTED: page %zu (huge page %zu) is ALL ZEROS\n",
> +				page_idx,
> +				(page_idx * page_size) / pmd_pagesize);

Since page_size and pmd_pagesize are uint64_t, the division result is 
uint64_t. Can using the %zu format specifier here misalign the va_list 
arguments on 32-bit architectures?

> +		} else {
> +			ksft_print_msg(
> +				"CORRUPTED: page %zu (huge page %zu): expected idx %zu, got %lu\n",
> +				page_idx, (page_idx * page_size) / pmd_pagesize,
> +				page_idx, (unsigned long)got_idx);
> +		}
> +		return false;
> +	}
> +	return true;
> +}

The fill_page() function initializes the page with FILL_BYTE (0xAF), but 
check_page() only verifies the 8-byte index at the beginning. Does this code 
miss partial corruptions that leave the first 8 bytes intact, since the rest 
of the page is never verified when got_idx == expected_idx?

[ ... ]
> +/* Run a single iteration. Returns total number of corrupted pages. */
> +static size_t run_iteration(void)
> +{
[ ... ]
> +	create_readers(threads, args, mmap_base, &ctl);
> +
> +	for (i = 0; i < TOTAL_PAGES; i++) {
> +		if (i % PUNCH_INTERVAL != 0)
> +			continue;
> +		if (madvise(mmap_base + i * page_size,
> +			    PUNCH_SIZE_FACTOR * page_size, MADV_REMOVE) != 0) {
> +			ksft_exit_fail_msg(
> +				"madvise(MADV_REMOVE) failed on page %zu: %d\n",
> +				i, errno);
> +		}
> +
> +		i += PUNCH_SIZE_FACTOR - 1;
> +	}
> +
> +	atomic_store_explicit(&ctl.stop, 1, memory_order_release);

For a typical x86 system with 2MB PMD and 4KB base pages, TOTAL_PAGES is 2560 
and the punch loop advances by 50, meaning it executes only about 51 times. 
Could the main thread finish this loop and set ctl.stop = 1 before the reader 
threads are fully scheduled and begin their verification loops? 

If this occurs, the readers would skip their loops entirely and 
reader_failures would be 0, allowing the test to silently pass without 
actually testing the race condition. Would a synchronization primitive like a 
pthread_barrier_t ensure the readers start before the main thread punches 
holes?

[ ... ]
> +static void thp_cleanup_handler(int signum)
> +{
> +	thp_restore_settings();
> +	/*
> +	 * Restore default handler and re-raise the signal to exit.
> +	 * This is to ensure the test process exits with the correct
> +	 * status code corresponding to the signal.
> +	 */
> +	signal(signum, SIG_DFL);
> +	raise(signum);
> +}

The thp_restore_settings() function calls thp_write_settings(), which uses 
standard I/O functions like fopen and fprintf. Since these are not 
async-signal-safe, can calling them from SIGINT and SIGTERM handlers risk 
deadlocks or heap corruption if the program is interrupted while inside a 
non-reentrant libc function?

